css:
body {
  font-family: Arial, sans-serif;
  font-size: 13px;
  color: #1a1a1a;
}

.handover-cert {
  max-width: 820px;
  margin: 0 auto;
}

/* ── HEADER ── */
.hc-header {
  text-align: center;
  border-bottom: 3px solid #2c5f2e;
  padding-bottom: 12px;
  margin-bottom: 16px;
}
.hc-header h1 {
  margin: 0;
  font-size: 22px;
  color: #2c5f2e;
  letter-spacing: 2px;
}
.hc-header h2 {
  margin: 4px 0 0;
  font-size: 13px;
  font-weight: normal;
  color: #555;
}

.hc-title-block {
  text-align: center;
  margin: 0 0 20px;
}
.hc-title-block span {
  font-size: 16px;
  font-weight: bold;
  letter-spacing: 3px;
  border: 2px solid #2c5f2e;
  padding: 4px 18px;
  color: #2c5f2e;
}

/* ── META GRID ── */
.meta-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0 40px;
  margin-bottom: 20px;
}
.meta-block h4 {
  margin: 0 0 6px;
  font-size: 11px;
  text-transform: uppercase;
  color: #888;
  border-bottom: 1px solid #ddd;
  padding-bottom: 3px;
}
.meta-block p {
  margin: 3px 0;
  font-size: 13px;
}
.meta-block .label {
  color: #666;
  font-size: 11px;
}

/* ── SECTION TITLE ── */
.hc-section-title {
  font-weight: bold;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.8px;
  border-bottom: 2px solid #2c5f2e;
  padding-bottom: 4px;
  margin: 22px 0 10px;
  color: #2c5f2e;
}

/* ── DETAILS TABLE ── */
.schedule {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
}
.schedule thead th {
  background: #2c5f2e;
  color: #fff;
  padding: 8px 10px;
  text-align: left;
  font-size: 12px;
}
.schedule tbody td {
  padding: 8px 10px;
  border-bottom: 1px solid #eee;
  font-size: 13px;
}
.schedule tbody tr:last-child td {
  border-bottom: none;
}
.hc-lbl {
  background: #f0f7f0;
  font-weight: bold;
  font-size: 11px;
  width: 20%;
  white-space: nowrap;
  color: #2c5f2e;
}

/* ── DECLARATION ── */
.hc-declaration {
  border-left: 4px solid #2c5f2e;
  background: #f0f7f0;
  padding: 12px 16px;
  margin: 16px 0;
  line-height: 1.8;
  font-size: 13px;
}

/* ── PARTIES TABLE ── */
.hc-parties {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 6px;
}
.hc-parties th {
  background: #2c5f2e;
  color: #fff;
  padding: 8px 12px;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  text-align: left;
  width: 50%;
}
.hc-parties td {
  border: 1px solid #ddd;
  padding: 12px;
  vertical-align: top;
  width: 50%;
}
.hc-pf {
  margin-bottom: 5px;
}
.hc-plbl {
  font-weight: bold;
  font-size: 11px;
  color: #2c5f2e;
}

/* ── NOTES ── */
.hc-notes {
  border: 1px solid #ddd;
  background: #fffef0;
  padding: 10px 14px;
  white-space: pre-wrap;
  margin-bottom: 6px;
  line-height: 1.6;
}

/* ── SIGNATURES ── */
.hc-sigs {
  width: 100%;
  border-collapse: collapse;
  margin-top: 8px;
}
.hc-sigs td {
  text-align: center;
  padding: 10px 20px;
  vertical-align: bottom;
}
.hc-sig-space {
  height: 55px;
}
.hc-sig-line {
  border-top: 1px solid #2c5f2e;
  margin-bottom: 6px;
}
.hc-sig-name {
  font-weight: bold;
  font-size: 12px;
}
.hc-sig-sub {
  font-size: 11px;
  color: #555;
  margin-top: 2px;
}
.hc-sig-date {
  font-size: 11px;
  color: #888;
  margin-top: 10px;
}

/* ── FOOTER ── */
.footer {
  border-top: 1px solid #ddd;
  padding-top: 10px;
  margin-top: 20px;
  font-size: 11px;
  color: #888;
  text-align: center;
}
